class ConcurrencyQueue {
  constructor(limit) {
    this.limit = limit;
    this.active = 0;
    this.queue = [];
  }

  add(task) {
    return new Promise((resolve, reject) => {
      this.queue.push({ task, resolve, reject });
      this.next();
    });
  }

  next() {
    if (this.active >= this.limit || this.queue.length === 0) return;

    const { task, resolve, reject } = this.queue.shift();
    this.active++;

    task()
      .then(resolve)
      .catch(reject)
      .finally(() => {
        this.active--;
        this.next();
      });
  }
}

